<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/security/bootstrap.php';

function h($v): string {return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function bytesLabel($bytes): string {$bytes=max(0,(float)$bytes);$u=['B','KB','MB','GB','TB'];$i=0;while($bytes>=1024&&$i<count($u)-1){$bytes/=1024;$i++;}return number_format($bytes,$i?2:0).' '.$u[$i];}
function redirectSecurity(string $message='',string $type='success'): never {if($message!=='')$_SESSION['ah_security_flash']=['message'=>$message,'type'=>$type];header('Location: seguridad.php');exit;}

if(isset($_GET['download_backup'])){
    $row=$security->backupById((int)$_GET['download_backup']);
    if(!$row||$row['status']!=='ready'||!is_file($row['path'])){http_response_code(404);exit('Respaldo no encontrado.');}
    $real=realpath($row['path']);$storage=realpath($security->storagePath());
    if(!$real||!$storage||!str_starts_with($real,$storage)){http_response_code(403);exit('Ruta no autorizada.');}
    header('Content-Type: application/zip');header('Content-Disposition: attachment; filename="'.basename($row['filename']).'"');header('Content-Length: '.filesize($real));header('X-Content-Type-Options: nosniff');readfile($real);exit;
}

if($_SERVER['REQUEST_METHOD']==='POST'){
    try{
        ahSecurityVerifyCsrf();$action=(string)($_POST['action']??'');
        if($action==='scan_quick'||$action==='scan_full'){$mode=$action==='scan_full'?'full':'quick';set_time_limit(240);$r=$security->scan($mode,$securityUserLabel,false);redirectSecurity("Escaneo $mode finalizado: {$r['files_scanned']} archivos y {$r['findings_count']} hallazgos.");}
        if($action==='baseline'){set_time_limit(240);$r=$security->createBaseline($securityUserLabel);redirectSecurity("Línea base actualizada con {$r['files']} archivos.");}
        if($action==='backup'){set_time_limit(300);$r=$security->createCodeBackup($securityUserLabel,'Respaldo manual');redirectSecurity("Respaldo creado: {$r['filename']} (".bytesLabel($r['size_bytes']).").");}
        if($action==='git_push'){set_time_limit(480);$r=$security->backupCommitPush($securityUserLabel,trim((string)($_POST['commit_message']??'')));redirectSecurity("Respaldo y push completados en {$r['remote']}/{$r['branch']}.");}
        if($action==='clamav'){set_time_limit(1800);$r=$security->runClamAv($securityUserLabel);redirectSecurity($r['infected']?'ClamAV detectó archivos infectados.':'ClamAV finalizó sin infecciones.',$r['infected']?'error':'success');}
        if($action==='clean_tmp'){$r=$security->cleanSafeTemporaryFiles($securityUserLabel,24);redirectSecurity('Limpieza segura finalizada: '.number_format((int)$r['deleted']).' archivos y '.bytesLabel((int)$r['released_bytes']).' liberados'.((int)$r['failed']?' · '.number_format((int)$r['failed']).' no pudieron eliminarse.':'.'),(int)$r['failed']?'error':'success');}
        if($action==='quarantine'){$security->quarantineFinding((int)$_POST['finding_id'],$securityUserLabel);redirectSecurity('Archivo movido a cuarentena.');}
        if($action==='ignore'){$security->ignoreFinding((int)$_POST['finding_id'],$securityUserLabel);redirectSecurity('Hallazgo ignorado.');}
        if($action==='reopen'){$security->reopenFinding((int)$_POST['finding_id'],$securityUserLabel);redirectSecurity('Hallazgo reabierto.');}
        if($action==='restore'){$security->restoreQuarantine((int)$_POST['quarantine_id'],$securityUserLabel);redirectSecurity('Archivo restaurado.');}
        if($action==='delete_backup'){$security->deleteBackup((int)$_POST['backup_id'],$securityUserLabel);redirectSecurity('Respaldo eliminado.');}
        throw new RuntimeException('Acción no reconocida.');
    }catch(Throwable $e){redirectSecurity($e->getMessage(),'error');}
}

$flash=$_SESSION['ah_security_flash']??null;unset($_SESSION['ah_security_flash']);
$statusFilter=trim((string)($_GET['status']??'open'));$severityFilter=trim((string)($_GET['severity']??''));
$dashboard=$security->dashboard();$findings=$security->findings($statusFilter,$severityFilter,400);$backups=$security->backups(40);$scans=$security->recentScans(12);$csrf=ahSecurityCsrfToken();$tmp=$security->temporaryStorageStatus(24);
$open=(int)($dashboard['findings']['open_total']??0);$high=(int)($dashboard['findings']['critical_total']??0)+(int)($dashboard['findings']['high_total']??0);$lastScan=$dashboard['last_scan'];$health=$dashboard['health'];$git=$dashboard['git'];
?>
<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Centro de Seguridad | Acción Honduras</title>
<style>
:root{--p:#34859b;--p2:#46b094;--bg:#f4f7f9;--card:#fff;--line:#dfe8ec;--text:#19313a;--muted:#667b84;--red:#b42318;--orange:#b54708;--green:#067647}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:Inter,Segoe UI,Arial,sans-serif;display:flex;min-height:100vh}.main{flex:1;min-width:0;padding:28px 34px 60px}.header{display:flex;justify-content:space-between;gap:20px;align-items:flex-start;margin-bottom:22px}.header h1{margin:0;font-size:28px}.header p{margin:7px 0 0;color:var(--muted)}.user{background:#e8f5f2;border:1px solid #c9e8e0;border-radius:999px;padding:9px 14px;font-weight:700;font-size:13px}.metrics{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px;margin-bottom:18px}.metric,.panel{background:var(--card);border:1px solid var(--line);border-radius:16px;box-shadow:0 5px 18px rgba(24,55,66,.05)}.metric{padding:18px}.metric span{display:block;color:var(--muted);font-size:12px;font-weight:800;text-transform:uppercase}.metric strong{display:block;font-size:28px;margin-top:7px}.metric small{color:var(--muted)}.danger strong{color:var(--red)}.panel{padding:20px;margin-bottom:18px}.panel h2{margin:0 0 15px;font-size:18px}.actions{display:flex;flex-wrap:wrap;gap:10px}.btn{border:0;border-radius:9px;padding:10px 14px;font-weight:800;cursor:pointer;background:var(--p);color:#fff;text-decoration:none;display:inline-block}.btn.secondary{background:#fff;color:var(--p);border:1px solid #b9d8e0}.btn.green{background:var(--green)}.btn.orange{background:var(--orange)}.btn.red{background:var(--red)}.btn.gray{background:#667085}.btn:disabled{opacity:.5}.grid2{display:grid;grid-template-columns:1.15fr .85fr;gap:18px}.checks{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}.check{border:1px solid var(--line);border-radius:10px;padding:11px;background:#fbfdfd}.check b{display:block;font-size:13px}.check span{font-size:12px;color:var(--muted)}.ok{color:var(--green)}.bad{color:var(--red)}.flash{padding:13px 15px;border-radius:10px;margin-bottom:18px;font-weight:700}.flash.success{background:#ecfdf3;color:#067647;border:1px solid #abefc6}.flash.error{background:#fef3f2;color:#b42318;border:1px solid #fecdca}.table-wrap{overflow:auto;border:1px solid var(--line);border-radius:12px}table{width:100%;border-collapse:collapse;background:#fff;min-width:900px}th,td{padding:11px 12px;border-bottom:1px solid #edf1f3;text-align:left;vertical-align:top;font-size:13px}th{background:#f8fafb;color:#48616b;font-size:11px;text-transform:uppercase;position:sticky;top:0}.path{max-width:390px;word-break:break-word;font-family:Consolas,monospace}.evidence{max-width:320px;word-break:break-word;color:#52666f}.severity{display:inline-block;padding:5px 8px;border-radius:999px;font-weight:900;font-size:11px;text-transform:uppercase}.critical{background:#fee4e2;color:#912018}.high{background:#ffead5;color:#93370d}.medium{background:#fef0c7;color:#854a0e}.low{background:#eaf2ff;color:#1849a9}.filters{display:flex;gap:10px;align-items:end;flex-wrap:wrap;margin-bottom:12px}.filters label,.note{font-size:12px;color:var(--muted)}select,input[type=text]{display:block;margin-top:5px;border:1px solid #cddce1;border-radius:8px;padding:9px 11px;min-width:180px}.inline{display:inline}.mini{padding:7px 9px;font-size:11px}.gitbox{background:#f8fafb;border:1px solid var(--line);border-radius:12px;padding:14px}.confirm{display:none;position:fixed;inset:0;background:rgba(9,26,32,.58);z-index:1000;align-items:center;justify-content:center;padding:20px}.confirm.open{display:flex}.confirm-box{background:#fff;border-radius:16px;padding:22px;max-width:470px;width:100%}.confirm-actions{display:flex;justify-content:flex-end;gap:10px;margin-top:20px}@media(max-width:1100px){.metrics{grid-template-columns:repeat(2,1fr)}.grid2{grid-template-columns:1fr}.main{padding:22px}.header{flex-direction:column}.checks{grid-template-columns:1fr}}
.tmp-meter{height:12px;border-radius:999px;background:#e7eef1;overflow:hidden;margin:12px 0 8px}.tmp-meter span{display:block;height:100%;background:linear-gradient(90deg,#46b094,#f79009,#d92d20);border-radius:999px}.tmp-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin:12px 0}.tmp-stats div{background:#f8fafb;border:1px solid var(--line);border-radius:10px;padding:11px}.tmp-stats span{display:block;color:var(--muted);font-size:11px;text-transform:uppercase;font-weight:800}.tmp-stats strong{display:block;margin-top:4px}.tmp-warning{padding:11px;border-radius:9px;background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;font-size:12px;margin:12px 0}@media(max-width:700px){.tmp-stats{grid-template-columns:1fr}}
</style></head><body>
<?php if(is_file(__DIR__.'/sidebar.php'))include __DIR__.'/sidebar.php'; ?>
<main class="main"><div class="header"><div><h1>Centro de Seguridad</h1><p>Escaneo, cuarentena, línea base, respaldo de código y GitHub para public_html.</p></div><div class="user"><?=h($securityUserLabel)?> · Administrador</div></div>
<?php if($flash):?><div class="flash <?=h($flash['type'])?>"><?=h($flash['message'])?></div><?php endif;?>
<section class="metrics"><div class="metric <?=$high?'danger':''?>"><span>Críticos y altos</span><strong><?=number_format($high)?></strong><small>Hallazgos abiertos</small></div><div class="metric"><span>Total por revisar</span><strong><?=number_format($open)?></strong><small>Todos los niveles</small></div><div class="metric"><span>Último escaneo</span><strong style="font-size:18px"><?=h($lastScan['finished_at']??'Nunca')?></strong><small><?=$lastScan?number_format((int)$lastScan['files_scanned']).' archivos':'Cree primero la línea base'?></small></div><div class="metric"><span>Último respaldo</span><strong style="font-size:18px"><?=h($dashboard['last_backup']['created_at']??'Nunca')?></strong><small><?=isset($dashboard['last_backup']['size_bytes'])?bytesLabel($dashboard['last_backup']['size_bytes']):'Código de public_html'?></small></div></section>
<section class="panel"><h2>Acciones protegidas</h2><div class="actions">
<?php foreach([['scan_quick','Escaneo rápido',''],['scan_full','Escaneo completo','El escaneo completo puede tardar varios minutos.'],['baseline','Actualizar línea base','La línea base declarará el código actual como aprobado.'],['backup','Respaldar código','']] as [$a,$label,$confirm]):?><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="<?=h($a)?>"><button class="btn <?=$a==='backup'?'green':($a==='scan_quick'?'':'secondary')?> <?=$confirm?'confirmable':''?>" <?=$confirm?'data-confirm="'.h($confirm).'"':''?>><?=h($label)?></button></form><?php endforeach;?>
<?php if($health['clamav_available']):?><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="clamav"><button class="btn orange confirmable" data-confirm="Se ejecutará ClamAV sobre public_html.">Ejecutar ClamAV</button></form><?php endif;?></div><p class="note">La cuarentena no elimina: mueve fuera de public_html y permite restaurar. El escáner heurístico requiere revisión humana.</p></section>
<div class="grid2"><section class="panel"><h2>Salud del servidor</h2><div class="checks">
<?php foreach([['Almacenamiento privado',$health['storage_writable'],$health['storage_path']],['Repositorio Git',$health['is_git_repo'],$health['is_git_repo']?'Detectado':'No detectado'],['Comando Git',$health['git_available'],$health['git_version']],['ClamAV',$health['clamav_available'],$health['clamav_version']?:'Opcional'],['ZipArchive',$health['zip_available'],$health['zip_available']?'Disponible':'No disponible'],['Procesos',$health['exec_available'],$health['exec_available']?'Disponible':'proc_open deshabilitado']] as [$label,$ok,$detail]):?><div class="check"><b class="<?=$ok?'ok':'bad'?>">● <?=h($label)?></b><span><?=h($detail)?></span></div><?php endforeach;?></div><p class="note">Espacio libre: <b><?=bytesLabel($health['disk_free'])?></b>.</p></section>
<section class="panel"><h2>GitHub</h2><div class="gitbox"><div><b>Rama:</b> <?=h($git['branch']??'—')?></div><div><b>Remoto:</b> <?=h($git['remote']??'—')?></div><div><b>Cambios:</b> <?=number_format((int)($git['changes_count']??0))?></div><div><b>Último commit:</b> <?=h($git['last_commit']??'—')?></div></div><form method="post" style="margin-top:12px"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="git_push"><label class="note">Mensaje del commit<input type="text" name="commit_message" style="width:100%" placeholder="Respaldo AF-2027"></label><button class="btn green confirmable" style="margin-top:10px" data-confirm="Se hará ZIP privado, commit y push. Se bloquea si hay alertas altas.">Respaldar, commit y push</button></form><p class="note">No guarda contraseñas de GitHub; usa SSH o la credencial ya configurada.</p></section></div>
<section class="panel"><h2>Almacenamiento temporal seguro</h2><p class="note">Diagnóstico de <code>/tmp</code>. La limpieza solo considera archivos regulares del usuario del sitio, con prefijos temporales reconocidos y más de 24 horas.</p><div class="tmp-meter" title="Uso de capacidad en /tmp"><span style="width:<?=min(100,max(0,(float)$tmp['used_percent']))?>%"></span></div><div class="tmp-stats"><div><span>Capacidad utilizada</span><strong><?=number_format((float)$tmp['used_percent'],1)?>%</strong></div><div><span>Espacio libre</span><strong><?=bytesLabel($tmp['free'])?></strong></div><div><span>Inodos utilizados</span><strong><?=number_format((float)$tmp['inode_used_percent'],1)?>%</strong></div><div><span>Inodos libres</span><strong><?=number_format((int)$tmp['inode_free'])?></strong></div><div><span>Limpieza permitida</span><strong><?=number_format((int)$tmp['safe_files'])?> archivos · <?=bytesLabel($tmp['safe_bytes'])?></strong></div></div><?php if(((float)$tmp['used_percent']>=95||(float)$tmp['inode_used_percent']>=95)&&!(int)$tmp['safe_files']):?><div class="tmp-warning"><b><code>/tmp</code> está saturado, pero el sitio no detecta archivos que pueda eliminar con seguridad.</b> Revise WHM: la ocupación pertenece probablemente a servicios del sistema, MySQL u otros usuarios.</div><?php endif;?><form method="post"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="clean_tmp"><button class="btn orange confirmable" <?=(int)$tmp['safe_files']===0?'disabled':''?> data-confirm="Solo se eliminarán <?=number_format((int)$tmp['safe_files'])?> archivos temporales reconocidos, propiedad del sitio y con más de 24 horas. No se tocarán sesiones, MySQL, carpetas ni archivos de otros usuarios.">Liberar temporales seguros</button></form></section>
<section class="panel"><h2>Hallazgos</h2><form method="get" class="filters"><label>Estado<select name="status"><?php foreach(['open'=>'Abiertos','ignored'=>'Ignorados','quarantined'=>'Cuarentena','restored'=>'Restaurados',''=>'Todos'] as $v=>$l):?><option value="<?=h($v)?>" <?=$statusFilter===$v?'selected':''?>><?=h($l)?></option><?php endforeach;?></select></label><label>Gravedad<select name="severity"><?php foreach([''=>'Todas','critical'=>'Crítica','high'=>'Alta','medium'=>'Media','low'=>'Baja'] as $v=>$l):?><option value="<?=h($v)?>" <?=$severityFilter===$v?'selected':''?>><?=h($l)?></option><?php endforeach;?></select></label><button class="btn secondary">Aplicar</button></form><div class="table-wrap"><table><thead><tr><th>Gravedad</th><th>Archivo</th><th>Regla</th><th>Evidencia</th><th>Estado</th><th>Acciones</th></tr></thead><tbody>
