<?php elseif($f['status']==='ignored'):?><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="reopen"><input type="hidden" name="finding_id" value="<?=(int)$f['id']?>"><button class="btn secondary mini">Reabrir</button></form>
<?php elseif($f['status']==='quarantined'):?><?php $stq=$db->prepare("SELECT id FROM ah_security_quarantine WHERE finding_id=? AND restored_at IS NULL ORDER BY id DESC LIMIT 1");$stq->execute([(int)$f['id']]);$qid=(int)$stq->fetchColumn();if($qid):?><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="restore"><input type="hidden" name="quarantine_id" value="<?=$qid?>"><button class="btn secondary mini confirmable" data-confirm="Se restaurará si la ruta original está libre.">Restaurar</button></form><?php endif;?><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></section>
<div class="grid2"><section class="panel"><h2>Respaldos privados</h2><div class="table-wrap"><table style="min-width:700px"><thead><tr><th>Fecha</th><th>Archivo</th><th>Tamaño</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php if(!$backups):?><tr><td colspan="5">Todavía no hay respaldos.</td></tr><?php endif;?><?php foreach($backups as $b):?><tr><td><?=h($b['created_at'])?></td><td class="path"><?=h($b['filename'])?><br><small>SHA-256: <?=h($b['sha256'])?></small></td><td><?=bytesLabel($b['size_bytes'])?></td><td><?=h($b['status'])?></td><td><?php if($b['status']==='ready'):?><a class="btn secondary mini" href="?download_backup=<?=(int)$b['id']?>">Descargar</a><form method="post" class="inline"><input type="hidden" name="csrf" value="<?=h($csrf)?>"><input type="hidden" name="action" value="delete_backup"><input type="hidden" name="backup_id" value="<?=(int)$b['id']?>"><button class="btn red mini confirmable" data-confirm="El ZIP se eliminará permanentemente.">Eliminar</button></form><?php endif;?></td></tr><?php endforeach;?></tbody></table></div></section><section class="panel"><h2>Historial de escaneos</h2><div class="table-wrap"><table style="min-width:600px"><thead><tr><th>Inicio</th><th>Modo</th><th>Archivos</th><th>Hallazgos</th><th>Estado</th></tr></thead><tbody><?php if(!$scans):?><tr><td colspan="5">Todavía no hay escaneos.</td></tr><?php endif;?><?php foreach($scans as $s):?><tr><td><?=h($s['started_at'])?></td><td><?=h($s['mode'])?></td><td><?=number_format((int)$s['files_scanned'])?></td><td><?=number_format((int)$s['findings_count'])?> · Altos: <?=number_format((int)$s['critical_count']+(int)$s['high_count'])?></td><td><?=h($s['status'])?></td></tr><?php endforeach;?></tbody></table></div></section></div>
</main><div class="confirm" id="confirmDialog"><div class="confirm-box"><h3>Confirmar acción</h3><p id="confirmText"></p><div class="confirm-actions"><button type="button" class="btn secondary" id="confirmCancel">Cancelar</button><button type="button" class="btn red" id="confirmAccept">Continuar</button></div></div></div>
<script>(()=>{let form=null;const d=document.getElementById('confirmDialog'),t=document.getElementById('confirmText');document.querySelectorAll('.confirmable').forEach(b=>b.addEventListener('click',e=>{e.preventDefault();form=b.closest('form');t.textContent=b.dataset.confirm||'¿Continuar?';d.classList.add('open')}));document.getElementById('confirmCancel').onclick=()=>{form=null;d.classList.remove('open')};document.getElementById('confirmAccept').onclick=()=>{if(form){d.classList.remove('open');form.submit()}}})();</script></body></html>
